parser_error_t parser_init_context(parser_context_t *ctx, const uint8_t *buffer, uint16_t bufferSize) {
    ctx->offset = 0;
    ctx->buffer = NULL;
    ctx->bufferLen = 0;

    if (bufferSize == 0 || buffer == NULL) {
        // Not available, use defaults
        return parser_init_context_empty;
    }

    ctx->buffer = buffer;
    ctx->bufferLen = bufferSize;
    return parser_ok;
}

parser_error_t parser_init(parser_context_t *ctx, const uint8_t *buffer, uint16_t bufferSize) {
    CHECK_ERROR(parser_init_context(ctx, buffer, bufferSize))
    return parser_ok;
}

const char *parser_getErrorDescription(parser_error_t err) {
    switch (err) {
        case parser_ok:
            return "No error";
        case parser_no_data:
            return "No more data";
        case parser_init_context_empty:
            return "Initialized empty context";
        case parser_display_idx_out_of_range:
            return "display_idx_out_of_range";
        case parser_display_page_out_of_range:
            return "display_page_out_of_range";
        case parser_unexpected_error:
            return "Unexpected internal error";
        case parser_unexpected_buffer_end:
            return "Unexpected buffer end";
        case parser_unexpected_value:
            return "unexpected_value";
        case parser_unexpected_number:
            return "unexpected_number";
        case parser_unexpected_version:
            return "unexpected_version";
        case parser_unexpected_characters:
            return "unexpected_characters";
        case parser_unexpected_field:
            return "unexpected_field";
        case parser_value_out_of_range:
            return "value_out_of_range";
        case parser_invalid_address:
            return "invalid_address";
        case parser_parsed_successfully:
            return "parsed_successfully";
        case parser_bad_length:
            return "bad_length";
        case parser_invalid_data:
            return "invalid_data";
        case parser_invalid_data_type:
            return "invalid_data_type";
        default:
            return "unrecognized error code";
    }
}

parser_error_t _read(parser_context_t *c, parser_tx_t *v) {
    if (c->buffer == NULL || c->bufferLen == 0) {
        return parser_no_data;
    }

    memset(v, 0, sizeof(parser_tx_t));

    CHECK_ERROR(zb_check_buffer_size(c, BLOCKTYPE_SIZE))
    CHECK_ERROR(zb_get_u8(c, (uint8_t *) &v->block_type))

    v->block_type = 0;

    //Check if we're dealing with a normal block or an account block
    uint64_t block_version = 0;
    CHECK_ERROR(zb_peek_u64(c, 1, &block_version))

    /*
    Only v1 blocks are supported in current API
    PROTOCOL_IMPLEMENTATION_VERSION = 1;
    */
    if (block_version != 1) {
        return parser_unexpected_value;
    }

    CHECK_ERROR(zb_check_buffer_size(c, BLOCKVERSION_SIZE))
    CHECK_ERROR(zb_get_u64(c, &v->version))

    CHECK_ERROR(zb_check_buffer_size(c, CHAINIDENTIFIER_SIZE))
    CHECK_ERROR(zb_get_u64(c, &v->chain_id))

    CHECK_ERROR(zb_check_buffer_size(c, BLOCKHEIGHT_SIZE))
    CHECK_ERROR(zb_get_u64(c, &v->block_height))
    CHECK_ERROR(parse_internal_block(c, v))

    return parser_ok;
}

/**
 * Check the full block is valid.
 */
parser_error_t parser_validate(const parser_context_t *c) {
    // We don't check any fields beyond the total size check
    // where the parser will fail if it encounters invalid data.
    if (c->offset != c->bufferLen) {
        return parser_unexpected_buffer_end;
    }
    return parser_ok;
}

int8_t cmp_block_type(block_type_e block, enum accounting_type_e type, enum token_standard_e standard) {
    // Standard of -1 is valid
    bool valid = block == TYPE_USER_TRANSACTION && type == 2 && standard == -1;
    valid |= block == TYPE_CONTRACT_TRANSACTION && type == 2 && standard == -1;
    valid |= block == TYPE_ACCOUNT_BLOCK && type == 2 && standard == -1;

    valid |= block == TYPE_ZTS_ISSUE && type == 3 && standard == 3;
    valid |= block == TYPE_ZTS_MINT && type == 3 && standard == 3;
    valid |= block == TYPE_ZTS_SWAP && type == 3 && standard == 3;
    valid |= block == TYPE_ZTS_UPDATE && type == 3 && standard == 3;

    valid |= block == TYPE_SENTINEL_REGISTER && type == 4 && standard == 4;
    valid |= block == TYPE_SENTINEL_COLLECT && type == 4 && standard == 4;
    valid |= block == TYPE_SENTINEL_REVOKE && type == 4 && standard == 4;

    valid |= block == TYPE_STAKE_START && type == 5 && standard == 5;
    valid |= block == TYPE_STAKE_UNLOCK && type == 5 && standard == 5;
    valid |= block == TYPE_STAKE_COLLECT && type == 5 && standard == 5;
    valid |= block == TYPE_STAKE_CANCEL && type == 5 && standard == 5;

    valid |= block == TYPE_PILLAR_REGISTER && type == 6 && standard == 6;
    valid |= block == TYPE_PILLAR_UPDATE && type == 6 && standard == 6;
    valid |= block == TYPE_PILLAR_REVOKE && type == 6 && standard == 6;
    valid |= block == TYPE_PILLAR_REGISTER_LEGACY && type == 6 && standard == 6;
    valid |= block == TYPE_PILLAR_UPDATE_LEGACY && type == 6 && standard == 6;
    valid |= block == TYPE_PILLAR_REVOKE_LEGACY && type == 6 && standard == 6;

    valid |= block == TYPE_PLASMA_FUSE && type == 7 && standard == 7;
    valid |= block == TYPE_PLASMA_CANCEL && type == 7 && standard == 7;

    valid |= block == TYPE_BRIDGE_NOMINATE && type == 8 && standard == 8;
    valid |= block == TYPE_BRIDGE_UNWRAP && type == 8 && standard == 8;
    valid |= block == TYPE_BRIDGE_WRAP && type == 8 && standard == 8;
    valid |= block == TYPE_BRIDGE_UPDATE && type == 8 && standard == 8;
    valid |= block == TYPE_BRIDGE_HALT && type == 8 && standard == 8;
    valid |= block == TYPE_BRIDGE_UNHALT && type == 8 && standard == 8;

    valid |= block == TYPE_SPORK_CREATE && type == 9 && standard == 9;
    valid |= block == TYPE_SPORK_ACTIVATE && type == 9 && standard == 9;

    valid |= block == TYPE_ACCELERATOR_CREATE && type == 10 && standard == 10;
    valid |= block == TYPE_ACCELERATOR_UPDATE && type == 10 && standard == 10;
    valid |= block == TYPE_ACCELERATOR_VOTE && type == 10 && standard == 10;

    return valid ? 0 : 1;
}

