parser_error_t parse_internal_block(parser_context_t *c, parser_tx_t *v) {
    CHECK_ERROR(zb_check_buffer_size(c, HASHSIZE_SIZE))
    CHECK_ERROR(zb_get_u8(c, &v->hash_size)) //32

    CHECK_ERROR(zb_check_buffer_size(c, PREVIOUSHASH_SIZE))
    CHECK_ERROR(zb_get_blob(c, v->previous_hash, PREVIOUSHASH_SIZE))

    CHECK_ERROR(zb_check_buffer_size(c, PRODUCERPUBLICKEY_SIZE))
    CHECK_ERROR(zb_get_blob(c, v->producer_public_key, PRODUCERPUBLICKEY_SIZE))

    CHECK_ERROR(zb_check_buffer_size(c, HEIGHT_SIZE))
    CHECK_ERROR(zb_get_u64(c, &v->height))

    CHECK_ERROR(zb_check_buffer_size(c, MOMENTUMACKNOWLEDGED_SIZE))
    CHECK_ERROR(zb_get_u64(c, &v->momentum_acknowledged))

    CHECK_ERROR(zb_check_buffer_size(c, ADDRESS_SIZE))
    CHECK_ERROR(zb_get_blob(c, v->address, ADDRESS_SIZE))

    CHECK_ERROR(zb_check_buffer_size(c, ADDRESSTO_SIZE))
    CHECK_ERROR(zb_get_blob(c, v->to_address, ADDRESSTO_SIZE))

    CHECK_ERROR(zb_check_buffer_size(c, AMOUNT_SIZE))
    CHECK_ERROR(zb_get_ZXX(c, &v->amount))

    CHECK_ERROR(zb_check_buffer_size(c, TOKENSTANDARD_SIZE))
    CHECK_ERROR(zb_get_blob(c, v->token_standard, TOKENSTANDARD_SIZE))

    CHECK_ERROR(zb_check_buffer_size(c, FROMPUBLICKEY_SIZE))
    CHECK_ERROR(zb_get_blob(c, v->from_public_key, FROMPUBLICKEY_SIZE))

    CHECK_ERROR(zb_check_buffer_size(c, DATAFIELDSIZE_SIZE))
    CHECK_ERROR(zb_get_u64(c, &v->data_field_size))

    // Data is array, data[data_field_size]
    CHECK_ERROR(zb_check_buffer_size(c, v->data_field_size))
    CHECK_ERROR(zb_get_raw_bytes(c, v->data, v->data_field_size))
    v->data_len = v->data_field_size;

    CHECK_ERROR(zb_check_buffer_size(c, DIFFICULTYTHRESHOLD_SIZE))
    CHECK_ERROR(zb_get_u64(c, &v->difficulty_threshold))

    CHECK_ERROR(zb_check_buffer_size(c, NONCE_SIZE))
    CHECK_ERROR(zb_get_u64(c, &v->nonce))

    CHECK_ERROR(zb_check_buffer_size(c, BASEPLASMACOMMITMENT_SIZE))
    CHECK_ERROR(zb_get_u64(c, &v->base_plasma_commitment))

    CHECK_ERROR(zb_check_buffer_size(c, USEDPLASMACOMMITMENT_SIZE))
    CHECK_ERROR(zb_get_u64(c, &v->used_plasma_commitment))

    CHECK_ERROR(zb_check_buffer_size(c, HEIGHTINFOMSG_SIZE))
    CHECK_ERROR(zb_get_u64(c, &v->height_info_msg))

    return parser_ok;
}

