static char buff_val[SCHNORR_BUF_MAX_SIZE];

parser_error_t parser_getItem(parser_context_t *ctx, uint8_t displayIdx, char *outKey, uint16_t outKeyLen,
                              char *outVal, uint16_t outValLen, uint8_t pageIdx, uint8_t *pageCount) {
    if (displayIdx == 0) {
        return parser_unexpected_value;
    }

    *pageCount = 1;
    MEMZERO(outKey, outKeyLen);
    MEMZERO(outVal, outValLen);
    MEMZERO(buff_val, sizeof(buff_val));
    uint8_t idx = displayIdx - 1;
    parser_tx_t *item = &app_context.block;

    bool expert_mode = app_mode_expert();
    uint8_t num_items = _getNumItems(ctx);
    if (displayIdx > num_items) {
        return parser_no_data;
    }

    parser_error_t err = parser_printItem(ctx, idx, outKey, outKeyLen, buff_val, sizeof(buff_val), expert_mode);
    if (err != parser_ok) {
        return err;
    }

