void h_review_loop_start() {
    if (viewFuncGetNumItems == NULL) {
        return;
    }

    viewdata.idx = 0;
    viewdata.pageIdx = 0;
    viewdata.pageCount = 1;
    viewdata.itemCount = viewFuncGetNumItems();
}

void h_review_loop_inside() {
    if (viewfuncGetItem == NULL) {
        return;
    }

    zxerr_t err = viewfuncGetItem(viewdata.idx,
                                   viewdata.key, MAX_CHARS_PER_KEY_LINE,
                                   viewdata.value, MAX_CHARS_PER_VALUE1_LINE,
                                   viewdata.value2, MAX_CHARS_PER_VALUE2_LINE,
                                   viewdata.pageIdx, &viewdata.pageCount);

    if (err != zxerr_ok) {
        viewdata.pageIdx = 0;
        viewdata.pageCount = 0;
        snprintf(viewdata.key, MAX_CHARS_PER_KEY_LINE, "ERROR");
        snprintf(viewdata.value, MAX_CHARS_PER_VALUE_LINE, "ERROR: %d", err);
        return;
    }

    if (viewdata.pageCount != 0) {
        uint8_t keyLen = strlen(viewdata.key);
        if (keyLen < MAX_CHARS_PER_KEY_LINE) {
            snprintf(viewdata.key + keyLen, MAX_CHARS_PER_KEY_LINE - keyLen, " [%d/%d]", viewdata.pageIdx + 1, viewdata.pageCount);
        }
    }
}

void h_review_loop_end() {
    if (viewdata.idx < viewdata.itemCount - 1) {
        viewdata.idx++;
        viewdata.pageIdx = 0;
        UX_FLOW_PREV();
        return;
    }

    // passed end of review
    viewdata.idx = 0;
    viewdata.pageIdx = 0;
}

